package com.lkl.studygroup.config; import org.springframework.boot.SpringApplication; import org.springframework.boot.env.EnvironmentPostProcessor; import org.springframework.core.env.ConfigurableEnvironment; import org.springframework.core.Ordered; public class EnvPrinterPostProcessor implements EnvironmentPostProcessor, Ordered { @Override public void postProcessEnvironment(ConfigurableEnvironment environment, SpringApplication application) { System.out.println("\n\n====== EARLY ENVIRONMENT VARIABLES DUMP ======"); System.out.println("DB_POSTGRES_URL: " + System.getenv("DB_POSTGRES_URL")); System.out.println("DB_USERNAME: " + System.getenv("DB_USERNAME")); System.out.println("DB_MONGO_URI: " + System.getenv("DB_MONGO_URI")); System.out.println("=============================================\n\n"); } @Override public int getOrder() { return Ordered.HIGHEST_PRECEDENCE; } }
